-- Generated INSERTs for April attendances
SET FOREIGN_KEY_CHECKS=0;
ON DUPLICATE KEY UPDATE expected_check_in=VALUES(expected_check_in), expected_check_out=VALUES(expected_check_out), check_in=VALUES(check_in), check_out=VALUES(check_out), early_leave_status=VALUES(early_leave_status), early_leave_approved_by=VALUES(early_leave_approved_by), early_leave_approved_at=VALUES(early_leave_approved_at), worked_minutes=VALUES(worked_minutes), is_completed=VALUES(is_completed), updated_at=NOW();
SET FOREIGN_KEY_CHECKS=1;
